#include <bits/stdc++.h>
using namespace std;

const int MOD = 100000000;
int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}
long long fib(int k) {
    if (k == 1 || k == 2) return 1;
    long long a = 1, b = 1;
    long long c;
    for (int i = 3; i <= k; ++i) {
        c = (a + b) % MOD;
        a = b;
        b = c;
    }
    return b;
}

int main() {
    int n, m;
    cin >> n >> m;
    int g = gcd(n, m);
    cout << fib(g) << endl;
    return 0;
}
